      return ICmpInst::isEquality(Pred) &&
             match(V, m_And(m_Value(X), m_APInt(Mask)));
    };

    if (MatchMaskedEq(V2, X, Mask, Pred2) && V1 == X) {
      // ICmp2 is (X & Mask) ==/!= C2, ICmp1 is X Pred1 C1.
      APInt InvMask = ~(*Mask);
      APInt MaxX = *C2 | InvMask;
      APInt MinX = *C2; // Min when all ~Mask bits are 0.

      if (IsAnd) {
        // (X Pred1 C1) & ((X & Mask) == C2) -> (X & Mask) == C2
        // if (X & Mask) == C2 implies X Pred1 C1.
        bool MaskedImpliesRange = false;
        if (Pred2 == ICmpInst::ICMP_EQ) {
          if (Pred1 == ICmpInst::ICMP_ULT)
            MaskedImpliesRange = MaxX.ult(*C1);
          else if (Pred1 == ICmpInst::ICMP_ULE)
            MaskedImpliesRange = MaxX.ule(*C1);
          else if (Pred1 == ICmpInst::ICMP_UGT)
            MaskedImpliesRange = MinX.ugt(*C1);
          else if (Pred1 == ICmpInst::ICMP_UGE)
            MaskedImpliesRange = MinX.uge(*C1);
          else if (Pred1 == ICmpInst::ICMP_SGT)
            MaskedImpliesRange = MinX.sgt(*C1);
          else if (Pred1 == ICmpInst::ICMP_SGE)
            MaskedImpliesRange = MinX.sge(*C1);
          else if (Pred1 == ICmpInst::ICMP_SLT)
            MaskedImpliesRange = MaxX.slt(*C1);
          else if (Pred1 == ICmpInst::ICMP_SLE)
            MaskedImpliesRange = MaxX.sle(*C1);
        }
        if (MaskedImpliesRange)
          return ICmp2;

        // (X Pred1 C1) & ((X & Mask) != C2) -> X Pred NewC
        // if the excluded set is at the boundary of the range.
        if (Pred2 == ICmpInst::ICMP_NE) {
          if (Pred1 == ICmpInst::ICMP_UGT && *C1 == *C2 - 1)
            return Builder.CreateICmp(ICmpInst::ICMP_UGT, X,
                                      ConstantInt::get(X->getType(), MaxX));
          if (Pred1 == ICmpInst::ICMP_UGE && *C1 == *C2)
            return Builder.CreateICmp(ICmpInst::ICMP_UGT, X,
                                      ConstantInt::get(X->getType(), MaxX));
        }
      } else {
        // (X Pred1 C1) | ((X & Mask) == C2) -> X Pred NewC
        // if the masked set is adjacent to the half-range.
        if (Pred2 == ICmpInst::ICMP_EQ) {
          if (Pred1 == ICmpInst::ICMP_ULT && C2->ule(*C1))
            return Builder.CreateICmp(
                ICmpInst::ICMP_ULT, X,
                ConstantInt::get(X->getType(),
                                 APIntOps::umax(*C1, MaxX + 1)));
          if (Pred1 == ICmpInst::ICMP_ULE && C2->ule(*C1 + 1))
            return Builder.CreateICmp(
                ICmpInst::ICMP_ULE, X,
                ConstantInt::get(X->getType(),
                                 APIntOps::umax(*C1, MaxX)));
        }
      }
    }

    if (MatchMaskedEq(V1, X, Mask, Pred1) && V2 == X) {
      // ICmp1 is (X & Mask) ==/!= C1, ICmp2 is X Pred2 C2.
      APInt InvMask = ~(*Mask);
      APInt MaxX = *C1 | InvMask;
      APInt MinX = *C1;

      if (IsAnd) {
        // (X & Mask) == C1 & (X Pred2 C2) -> (X & Mask) == C1
        // if (X & Mask) == C1 implies X Pred2 C2.
        bool MaskedImpliesRange = false;
        if (Pred1 == ICmpInst::ICMP_EQ) {
          if (Pred2 == ICmpInst::ICMP_ULT)
            MaskedImpliesRange = MaxX.ult(*C2);
          else if (Pred2 == ICmpInst::ICMP_ULE)
            MaskedImpliesRange = MaxX.ule(*C2);
          else if (Pred2 == ICmpInst::ICMP_UGT)
            MaskedImpliesRange = MinX.ugt(*C2);
          else if (Pred2 == ICmpInst::ICMP_UGE)
            MaskedImpliesRange = MinX.uge(*C2);
          else if (Pred2 == ICmpInst::ICMP_SGT)
            MaskedImpliesRange = MinX.sgt(*C2);
          else if (Pred2 == ICmpInst::ICMP_SGE)
            MaskedImpliesRange = MinX.sge(*C2);
          else if (Pred2 == ICmpInst::ICMP_SLT)
            MaskedImpliesRange = MaxX.slt(*C2);
          else if (Pred2 == ICmpInst::ICMP_SLE)
            MaskedImpliesRange = MaxX.sle(*C2);
        }
        if (MaskedImpliesRange)
          return ICmp1;

        // (X & Mask) != C1 & (X Pred2 C2) -> X Pred NewC
        if (Pred1 == ICmpInst::ICMP_NE) {
          if (Pred2 == ICmpInst::ICMP_UGT && *C2 == *C1 - 1)
            return Builder.CreateICmp(ICmpInst::ICMP_UGT, X,
                                      ConstantInt::get(X->getType(), MaxX));
          if (Pred2 == ICmpInst::ICMP_UGE && *C2 == *C1)
            return Builder.CreateICmp(ICmpInst::ICMP_UGT, X,
                                      ConstantInt::get(X->getType(), MaxX));
        }
      } else {
        // (X & Mask) == C1 | (X Pred2 C2) -> X Pred NewC
        if (Pred1 == ICmpInst::ICMP_EQ) {
          if (Pred2 == ICmpInst::ICMP_ULT && C1->ule(*C2))
            return Builder.CreateICmp(
                ICmpInst::ICMP_ULT, X,
                ConstantInt::get(X->getType(),
                                 APIntOps::umax(*C2, MaxX + 1)));
          if (Pred2 == ICmpInst::ICMP_ULE && C1->ule(*C2 + 1))
            return Builder.CreateICmp(
                ICmpInst::ICMP_ULE, X,
                ConstantInt::get(X->getType(),
                                 APIntOps::umax(*C2, MaxX)));
        }
      }
    }
  }
